SELECT * FROM houses


        AND (title LIKE CONCAT('%', #{req.keyword}, '%')
        OR description LIKE CONCAT('%', #{req.keyword}, '%')
        OR address LIKE CONCAT('%', #{req.keyword}, '%'))


        AND city = #{req.city}


        AND district = #{req.district}


        AND price >= #{req.minPrice}


        AND price <= #{req.maxPrice}


        AND house_type = #{req.houseType}


        AND owner_type = #{req.ownerType}


        AND rooms = #{req.rooms}


        AND decoration = #{req.decoration}

    AND status = 'ONLINE'


    ORDER BY price ASC
    ORDER BY price DESC
    ORDER BY view_count DESC
    ORDER BY create_time DESC
